import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import api from "../../api/axios";

export default function EditAppointment() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [appointment, setAppointment] = useState({
    lead: "",
    vehicle: "",
    appointmentType: "viewing",
    date: "",
    time: "",
    status: "scheduled",
    notes: "",
  });

  const [leads, setLeads] = useState([]);
  const [vehicles, setVehicles] = useState([]);

  useEffect(() => {
    const load = async () => {
      try {
        const [apptRes, leadRes, vehicleRes] = await Promise.all([
          api.get(`/appointments/${id}`),
          api.get("/leads"),
          api.get("/vehicles"),
        ]);

        const a = apptRes.data;

        setAppointment({
          lead: a.lead?._id || a.lead || "",
          vehicle: a.vehicle?._id || a.vehicle || "",
          appointmentType: a.appointmentType || "viewing",
          date: a.date ? String(a.date).slice(0, 10) : "",
          time: a.time || "",
          status: a.status || "scheduled",
          notes: a.notes || "",
        });

        setLeads(leadRes.data);
        setVehicles(vehicleRes.data);
      } catch (err) {
        alert(err.response?.data?.message || "Failed to load appointment");
        navigate("/appointments");
      }
    };

    load();
  }, [id, navigate]);

  const handleChange = (e) => {
    setAppointment({ ...appointment, [e.target.name]: e.target.value });
  };

  const submit = async (e) => {
    e.preventDefault();
    try {
      await api.put(`/appointments/${id}`, appointment);
      alert("Appointment updated!");
      navigate("/appointments");
    } catch (err) {
      alert(err.response?.data?.message || "Update failed");
    }
  };

  return (
    <div style={{ padding: 20, maxWidth: 520 }}>
      <h2>Edit Appointment (Staff)</h2>

      <form onSubmit={submit}>
        <label>Lead</label><br />
        <select name="lead" value={appointment.lead} onChange={handleChange} required style={{ width: "100%", padding: 8 }}>
          <option value="">Select Lead</option>
          {leads.map((l) => (
            <option key={l._id} value={l._id}>{l.name}</option>
          ))}
        </select>

        <br /><br />

        <label>Vehicle</label><br />
        <select name="vehicle" value={appointment.vehicle} onChange={handleChange} required style={{ width: "100%", padding: 8 }}>
          <option value="">Select Vehicle</option>
          {vehicles.map((v) => (
            <option key={v._id} value={v._id}>
              {v.brand} {v.model || v.type || ""} ({v.year})
            </option>
          ))}
        </select>

        <br /><br />

        <label>Type</label><br />
        <select
          name="appointmentType"
          value={appointment.appointmentType}
          onChange={handleChange}
          style={{ width: "100%", padding: 8 }}
        >
          <option value="viewing">Viewing</option>
          <option value="test_drive">Test Drive</option>
          <option value="follow_up">Follow Up</option>
        </select>

        <br /><br />

        <label>Date</label><br />
        <input type="date" name="date" value={appointment.date} onChange={handleChange} required style={{ width: "100%", padding: 8 }} />

        <br /><br />

        <label>Time</label><br />
        <input type="time" name="time" value={appointment.time} onChange={handleChange} required style={{ width: "100%", padding: 8 }} />

        <br /><br />

        <label>Status</label><br />
        <select name="status" value={appointment.status} onChange={handleChange} style={{ width: "100%", padding: 8 }}>
          <option value="scheduled">Scheduled</option>
          <option value="completed">Completed</option>
          <option value="cancelled">Cancelled</option>
        </select>

        <br /><br />

        <label>Notes</label><br />
        <textarea
          name="notes"
          value={appointment.notes}
          onChange={handleChange}
          rows={3}
          style={{ width: "100%", padding: 8 }}
          placeholder="Interaction notes"
        />

        <br /><br />

        <button type="submit" style={{ padding: "8px 12px" }}>
          Save Changes
        </button>
      </form>
    </div>
  );
}
